THE CLAIM:
{
 "title": "Buyer security audit adds a slow gate that delays first PO",
 "narrative": "The model assumes the venture can sell to large operators once it clears CE and TUV product certification. But those buyers require a separate security prequalification first, and each audit cycle runs one to two quarters. That serial delay compresses the Year-1 selling window and locks out gated accounts, so both factors are too high.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Large operators require security audits before listing networked power devices",
   "refs": [
    "digest:serviceable-benchmark#c13",
    "digest:serviceable-benchmark#c4",
    "ledger:serviceableFactor"
   ]
  },
  {
   "step": "propagation",
   "text": "New entrant builds this and passes audits within Year 1",
   "refs": [
    "profile:Stage",
    "profile:Who is the primary buyer you'll sell through first?"
   ]
  },
  {
   "step": "model-impact",
   "text": "Gate delays first PO and blocks gated accounts",
   "refs": [
    "ledger:obtainableFactor",
    "ledger:serviceableFactor"
   ]
  }
 ],
 "falsifier": "Two or more large CE operators issue rack-PDU RFQs in the first two quarters with no security prequalification, or confirm CE marking alone suffices for listing.",
 "category": "execution",
 "evidence": [
  {
   "title": "Security Guideline Product Security Sourcing Guide",
   "sourceType": "industry-report",
   "publisher": "NERC",
   "date": "2023-12-07",
   "excerpt": "Vendor-Level Risk Management ... Product Vulnerability Disclosure ... Current disclosure by the supplier: 'Push' or 'Pull' Process — documents formal vendor security prequalification artifacts for grid/critical-infrastructure buyers.",
   "url": "https://www.nerc.com/globalassets/who-we-are/standing-committees/rstc/scs/product-security-sourcing-guide.pdf",
   "attached": true
  },
  {
   "title": "Supply Chain Product Assurance Playbook (Schneider Electric)",
   "sourceType": "industry-report",
   "publisher": "NIST / Schneider Electric",
   "date": "2024-09-18",
   "excerpt": "SBOMs generated for all products starting January 2021 and every product release is compliant to ISA/IEC 62443-4-1 Secure Development Lifecycle. Globally SE is certified to 4-1 Maturity Level 4 — incumbents already carry the security-gate artifacts a new entrant must build.",
   "url": "https://csrc.nist.gov/csrc/media/Presentations/2024/supply-chain-product-assurance-playbook/images-media/20240918-FINAL%20CG%20SE%20September%202024%20SSCA%20Presentation%20v2.pdf",
   "attached": true
  },
  {
   "title": "CRA FAQ - Transition period",
   "sourceType": "industry-report",
   "publisher": "Open Regulatory Compliance Working Group",
   "date": null,
   "excerpt": "The obligations of manufacturers to ensure that products with digital elements are in conformity with the essential cybersecurity requirements ... apply from 11 December 2027 — the binding CRA gate is prospective, tempering the near-term regulatory pressure.",
   "url": "https://cra.orcwg.org/faq/official/transition/",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "serviceableFactor",
  "label": "Serviceable share of TAM",
  "kind": "assumption",
  "value": 0.55,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "needs-source",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.45,
   "high": 0.65
  },
  "funnelActive": true,
  "derivation": {
   "method": "Reachability assumption",
   "expression": "No public SAM/TAM benchmark for B2B hardware exists; EU cert stack (EN 50600, ecodesign 2019/424, CE/TÜV) justifies < 1.0 but doesn't quantify 0.55"
  },
  "provenance": {
   "rationale": "Assumption leaf — channel + regulatory reach; EU certification barriers documented qualitatively only.",
   "promotionPath": "Bottom-up channel-coverage model (named accounts × reachable share) → sourced serviceable %."
  },
  "evidence": [
   {
    "title": "EU ecodesign requirements for servers and data storage (2019/424)",
    "sourceType": "industry-report",
    "publisher": "EUR-Lex",
    "date": "2019",
    "excerpt": "EU ecodesign and certification requirements gate which demand is regulatory-clear for a new entrant — the qualitative basis of the serviceable haircut.",
    "attached": true
   }
  ]
 },
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.01,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.005,
   "high": 0.03
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Prospeo assigns 1% of SAM to YEAR 1 (3% and 5% are Years 2–3) — the prior 3% read the Year-2 figure as Year 1. Corrected to 1%; the Tractian comparable (first-year ~$1.2M against a multi-$B market) sits below 1%.",
   "crossCheck": "Early-procurement mechanism (DC electrical gear locked 12–24mo before fit-out) independently supports ≤2%; open 2026 EU rack-PDU tenders keep 2–3% inside the band."
  },
  "provenance": {
   "rationale": "Refinement cycle 1 caught the benchmark-period misread — the value now follows the source's own Year-1 figure, band 0.5–3%.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
